import React, { useState } from "react";

function Dataset() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule3 = async () => {
    setLoading(true);

    try {
      const res = await fetch("http://localhost:5000/module3");
      const data = await res.json();
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Backend error");
    }

    setLoading(false);
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h2>Module 3: Dataset Builder</h2>

      <button onClick={runModule3}>Run Module 3</button>

      {loading && <p>Processing...</p>}

      {result && result.status === "success" && (
        <div>
          <h3>Output</h3>
          <p>Train Size: {result.train_size}</p>
          <p>Test Size: {result.test_size}</p>

          <h3>Labels Table (Test Data)</h3>

          <div style={{
            height: "400px",
            overflowY: "scroll",
            border: "1px solid black"
          }}>
            <table border="1" width="100%">
              <thead>
                <tr>
                  <th>Index</th>
                  <th>Label</th>
                </tr>
              </thead>

              <tbody>
                {result.y_test.map((val, index) => (
                  <tr key={index}>
                    <td>{index}</td>
                    <td>{val}</td>
                  </tr>
                ))}
              </tbody>

            </table>
          </div>

        </div>
      )}
    </div>
  );
}

export default Dataset;
